#include<bits/stdc++.h>
using namespace std;
const int N=5e7+5;
class FHQ_Treap
{
    private:
    struct node
    {
        int l,r;
        int val,key;
        int siz;
    }t[N];
    int root[N],tot,cnt;
    int newnode(int v)
    {
        t[++tot].val=v;
        t[tot].key=rand();
        t[tot].siz=1;
        return tot;
    }
    int copynode(int v)
    {
        t[++tot]=t[v];
        return tot;
    }
    void pushup(int x)
    {
        t[x].siz=t[t[x].l].siz+t[t[x].r].siz+1;
    }
    void split(int p,int v,int &x,int &y)
    {
        if(p==0)
        {
            x=y=0;
            return;
        }
        int now=copynode(p);
        if(t[p].val<=v)
        {
            x=now;
            split(t[p].r,v,t[x].r,y);
        }
        else
        {
            y=now;
            split(t[p].l,v,x,t[y].l);
        }
        pushup(now);
    }
    int merge(int x,int y)
    {
        if(x==0||y==0)
        {
            return x+y;
        }
        int now;
        if(t[x].key<t[y].key)
        {
            now=copynode(x);
            t[now].r=merge(t[now].r,y);
            pushup(now);
            return now;
        }
        else
        {
            now=copynode(y);
            t[now].l=merge(x,t[now].l);
            pushup(now);
            return now;
        }
    }
    public:
    int copyver(int v)
    {
        root[++cnt]=root[v];
        return cnt;
    }
    void insert(int ver,int v)
    {
        int x,y,z;
        split(root[ver],v,x,y);
        z=newnode(v);
        root[ver]=merge(merge(x,z),y);
    }
    void del(int ver,int v)
    {
        int x,y,z;
        split(root[ver],v,x,z);
        split(x,v-1,x,y);
        y=merge(t[y].l,t[y].r);
        root[ver]=merge(merge(x,y),z);
    }
    int getrnk(int ver,int v)
    {
        int x,y;
        split(root[ver],v-1,x,y);
        int ans=t[x].siz+1;
        root[ver]=merge(x,y);
        return ans-1;
    }
    private:
    int kth(int p,int v)
    {
        if(v<=t[t[p].l].siz)
        {
            return kth(t[p].l,v);
        }
        if(v==t[t[p].l].siz+1)
        {
            return p;
        }
        return kth(t[p].r,v-t[t[p].l].siz-1);
    }
    public:
    int getkth(int ver,int v)
    {
        return t[kth(root[ver],v+1)].val;
    }
    int getpre(int ver,int v)
    {
        int x,y;
        split(root[ver],v-1,x,y);
        int p=kth(x,t[x].siz);
        int ans=t[p].val;
        root[ver]=merge(x,y);
        return ans;
    }
    int getnxt(int ver,int v)
    {
        int x,y;
        split(root[ver],v,x,y);
        int p=kth(y,1);
        int ans=t[p].val;
        root[ver]=merge(x,y);
        return ans;
    }
    FHQ_Treap()
    {
        tot=cnt=0;
        insert(0,2147483647);
        insert(0,-2147483647);
    }
}t;
int main()
{
    int n;
    scanf("%d",&n);
    while(n--)
    {
        int op,x,v;
        scanf("%d%d%d",&v,&op,&x);
        int now=t.copyver(v);
        if(op==1)
        {
            t.insert(now,x);
        }
        else if(op==2)
        {
            t.del(now,x);
        }
        else if(op==3)
        {
            printf("%d\n",t.getrnk(now,x));
        }
        else if(op==4)
        {
            printf("%d\n",t.getkth(now,x));
        }
        else if(op==5)
        {
            printf("%d\n",t.getpre(now,x));
        }
        else
        {
            printf("%d\n",t.getnxt(now,x));
        }
    }
    return 0;
}
